#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
#define ls (id<<1)
#define rs (id<<1|1)
CI maxn=2e6+5;
int n,m;
struct node1
{
	int l,r;
}a[maxn];
vector<int>d;
int tot;
struct node2
{
	int lazy,maxa;
}t[maxn<<2];
inline int getid(int __x)
{
	return lower_bound(d.begin(),d.end(),__x)-d.begin()+1;
}
bool cmp(node1 __x,node1 __y)
{
	return __x.r-__x.l<__y.r-__y.l;
}
void update(int id)
{
	t[id].maxa=max(t[ls].maxa,t[rs].maxa);
}
void work(int id,int x)
{
	t[id].lazy+=x;
	t[id].maxa+=x;
}
void pushdown(int id)
{
	int x=t[id].lazy;
	if(x)
	{
		work(ls,x);
		work(rs,x);
		t[id].lazy=0;
	}
}
void change(int id,int l,int r,int _l,int _r,int x)//线段树
{
	if(l==_l&&r==_r)
	{
		work(id,x);
		return;
	}
	pushdown(id);
	int mid=(l+r)>>1;
	if(_r<=mid)
	{
		change(ls,l,mid,_l,_r,x);
	}
	else if(_l>mid)
	{
		change(rs,mid+1,r,_l,_r,x);
	}
	else
	{
		change(ls,l,mid,_l,mid,x);
		change(rs,mid+1,r,mid+1,_r,x);
	}
	update(id);
}
signed main()
{
	IOS
	cin.tie(0);
	cout.tie(0);
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>a[i].l>>a[i].r;
		d.pb(a[i].l);
		d.pb(a[i].r);
	}
	sort(a+1,a+n+1,cmp);
	sort(d.begin(),d.end());
	d.erase(unique(d.begin(),d.end()),d.end());//离散化
	int res=inf,j=1;
	tot=d.size();
	memset(t,0,sizeof(t));
	FOR(i,1,n)//双指针
	{
		change(1,1,tot,getid(a[i].l),getid(a[i].r),1);
		wh(t[1].maxa>=m&&j<=i)
		{
			res=min(res,(a[i].r-a[i].l)-(a[j].r-a[j].l));
			change(1,1,tot,getid(a[j].l),getid(a[j].r),-1);
			j++;
		}
	}
	if(res==inf)
	{
		cout<<-1<<'\n';
	}
	else
	{
		cout<<res<<'\n';
	}
	return false;
}
